public boolean dfs(ArrayList> graph, int source, int destination, boolean[] visit){
    if(source == destination){
        return true;
    }
    visit[source] = true;
    for(int x : graph.get(source)){
        if(!visit[x]){
            if(dfs(graph, x, destination, visit)){
                return true;
            }
        }
    }
    return false;
